using Newtonsoft.Json;

namespace PerfDiff;

internal sealed class BenchmarkFileReader
{
    private readonly ILogger<BenchmarkFileReader> logger;

    public BenchmarkFileReader(ILogger<BenchmarkFileReader> logger)
    {
        this.logger = logger;
    }

    public BenchmarkReport? ReadReport(string path)
    {
        try
        {
            using var reader = new StreamReader(path);
            using var jsonReader = new JsonTextReader(reader);
            var serializer = new JsonSerializer();
            return serializer.Deserialize<BenchmarkReport>(jsonReader);
        }
        catch (JsonSerializationException ex)
        {
            this.logger.LogError("Failed to deserialize benchmark report from {Path}", path);
            return null;
        }
    }
}
